/* =========================
   GERAR ID TEMPORÁRIO DA NOTÍCIA
========================= */
const dataAgora = new Date();
const yyyy = dataAgora.getFullYear();
const mm = String(dataAgora.getMonth() + 1).padStart(2, '0');
const dd = String(dataAgora.getDate()).padStart(2, '0');
const hh = String(dataAgora.getHours()).padStart(2, '0');
const min = String(dataAgora.getMinutes()).padStart(2, '0');
const ss = String(dataAgora.getSeconds()).padStart(2, '0');
const rand = Math.floor(Math.random() * 1000).toString().padStart(3, '0');

const id_post = `noticia_${yyyy}${mm}${dd}_${hh}${min}${ss}_${rand}`;

/* =========================
   EXTRAÇÃO DE IMAGENS
========================= */
const html = $json.data || $json.body || '';
let imagens = [];

/* 1️⃣ OG IMAGE */
const ogRegex = /<meta[^>]+property=["']og:image["'][^>]+content=["']([^"']+)["']/i;
const ogMatch = html.match(ogRegex);
if (ogMatch?.[1]) imagens.push(ogMatch[1]);

/* 2️⃣ TWITTER IMAGE */
const twitterRegex = /<meta[^>]+name=["']twitter:image["'][^>]+content=["']([^"']+)["']/i;
const twitterMatch = html.match(twitterRegex);
if (twitterMatch?.[1]) imagens.push(twitterMatch[1]);

/* 3️⃣ JSON-LD */
const jsonLdRegex = /<script type="application\/ld\+json">([\s\S]*?)<\/script>/gi;
let jsonMatch;

while ((jsonMatch = jsonLdRegex.exec(html)) !== null) {
  try {
    const json = JSON.parse(jsonMatch[1]);
    const graph = json['@graph'] || [json];

    graph.forEach(item => {
      if (item?.image?.url) imagens.push(item.image.url);
      if (item?.thumbnailUrl) imagens.push(item.thumbnailUrl);
      if (Array.isArray(item?.image)) {
        item.image.forEach(img => {
          if (typeof img === 'string') imagens.push(img);
          if (img?.url) imagens.push(img.url);
        });
      }
    });
  } catch (e) {}
}

/* 4️⃣ IMG TAGS */
const imgRegex = /<img[^>]+(?:src|data-src|data-original)=["']([^"']+)["']/gi;
let imgMatch;

while ((imgMatch = imgRegex.exec(html)) !== null) {
  let url = imgMatch[1];
  if (url.startsWith('//')) url = 'https:' + url;
  if (url.startsWith('http')) imagens.push(url);
}

/* LIMPEZA */
imagens = [...new Set(imagens)]
  .filter(u => !u.includes('logo') && !u.includes('icon'));

/* LIMITAR A 6 */
const imagensLimitadas = imagens.slice(0, 6);

/* =========================
   LINK DA NOTÍCIA (ITEM ATUAL)
========================= */
const linkNoticia = $('When Executed by Another Workflow').item.json.link || '';

/* =========================
   OUTPUT FINAL
========================= */
const output = {
  id_post,
  link_noticia: linkNoticia,
};

for (let i = 1; i <= 6; i++) {
  output[`imagem${i}`] = imagensLimitadas[i - 1] || '';
}

output.total_imagens = imagens.length;
output.imagem_consolidado = imagensLimitadas.join(', ');

return output;

/* =========================
   INPUT = ITEM FINAL DA NOTÍCIA
========================= */
const item = $json;

/* =========================
   COLETAR IMAGENS EM ARRAY
========================= */
let imagens = [];

for (let i = 1; i <= 6; i++) {
  imagens.push({
    imagem: item[`imagem${i}`] || '',
    avaliacao: item[`aval_imagem${i}`] || '',
    comentario: item[`com_imagem${i}`] || '',
    status: item[`stat_imagem${i}`] || 'rejeitada',
  });
}

/* =========================
   ORDENAR: APROVADAS PRIMEIRO
========================= */
const aprovadas = imagens.filter(i => i.status === 'aprovada' && i.imagem);
const rejeitadas = imagens.filter(i => i.status !== 'aprovada' || !i.imagem);

const ordenado = [...aprovadas, ...rejeitadas].slice(0, 6);

/* =========================
   RECONSTRUIR OUTPUT
========================= */
const output = {
  id_post: item.id_post,
  link_noticia: item.link_noticia,
};

/* Slots fixos */
for (let i = 1; i <= 6; i++) {
  const img = ordenado[i - 1] || {};

  output[`imagem${i}`] = img.imagem || '';
  output[`aval_imagem${i}`] = img.avaliacao || '';
  output[`com_imagem${i}`] = img.comentario || '';
  output[`stat_imagem${i}`] = img.imagem ? (img.status || 'rejeitada') : 'rejeitada';
}

/* =========================
   METADADOS
========================= */
output.total_imagens = item.total_imagens || 0;

/* Recalcular consolidado só com URLs válidas */
output.imagem_consolidado = ordenado
  .map(i => i.imagem)
  .filter(Boolean)
  .join(', ');

return output;

/* =========================
   CONTEXTO DA NOTÍCIA (ITEM CORRETO)
========================= */
const contexto = $('Imagem encontrada?1').item.json;

const id_post = contexto.id_post;
const link_noticia = contexto.link_noticia;

/* =========================
   LIMPAR E PARSEAR JSON DO ANALYZE IMAGE
========================= */
const raw = $json.content || '';

const clean = raw
  .replace(/```json/gi, '')
  .replace(/```/g, '')
  .trim();

let parsed = { imagens: [] };

try {
  parsed = JSON.parse(clean);
} catch (e) {
  // se der erro, segue com array vazio
}

/* =========================
   OUTPUT BASE
========================= */
const output = {
  id_post,
  link_noticia
};

/* =========================
   CAMPOS FIXOS (1 a 6)
========================= */
for (let i = 1; i <= 6; i++) {
  // imagem
  output[`imagem${i}`] = contexto[`imagem${i}`] || '';

  // avaliação
  output[`aval_imagem${i}`] = '';
  output[`com_imagem${i}`] = '';

  // default = rejeitada
  output[`stat_imagem${i}`] = 'rejeitada';
}

/* =========================
   APLICAR AVALIAÇÕES RECEBIDAS
========================= */
(parsed.imagens || []).forEach(img => {
  const idx = img.idx;

  if (idx >= 1 && idx <= 6) {
    output[`aval_imagem${idx}`] = img.avaliacao || '';
    output[`com_imagem${idx}`] = img.comentario || '';

    if (img.status) {
      output[`stat_imagem${idx}`] = img.status;
    }
  }
});

/* =========================
   METADADOS
========================= */
output.total_imagens = contexto.total_imagens || 0;
output.imagem_consolidado = contexto.imagem_consolidado || '';

return output;

/* =========================
   CONTEXTO DA NOTÍCIA (ITEM CORRETO)
========================= */
const contexto = $('Imagem encontrada?1').item.json;

const id_post = contexto.id_post || '';
const link_noticia = contexto.link_noticia || '';

/* =========================
   OUTPUT BASE (SEM IMAGENS)
========================= */
const output = {
  id_post,
  link_noticia
};

/* =========================
   CAMPOS FIXOS (1 a 6) - TUDO VAZIO / REJEITADA
========================= */
for (let i = 1; i <= 6; i++) {
  output[`imagem${i}`] = '';
  output[`aval_imagem${i}`] = '';
  output[`com_imagem${i}`] = '';
  output[`stat_imagem${i}`] = 'rejeitada';
}

/* =========================
   METADADOS
========================= */
output.total_imagens = 0;
output.imagem_consolidado = '';

return output;
